mapper.insert:
SELECT 'DOCUMENT_' || TO_CHAR(SYSDATE, 'YYMM') || '_' || LPAD( NVL(MAX(TO_NUMBER(SUBSTR(document_id, -4))), 0) + 1, 4, '0' ) FROM document WHERE document_id LIKE 'DOCUMENT_' || TO_CHAR(SYSDATE, 'YYMM') || '_%'
insert into document ( document_id, project_id, document_category_id, version_id, milestone_id, created_by, title, description, setting_code_id
status_code,
status_name,
) values ( #{documentId}, #{projectId}, #{documentCategoryId}, #{versionId}, #{milestoneId}, #{createdBy}, #{title}, #{description}, #{settingCodeId}
#{statusCode},
#{statusName},
)

mapper.select:
SELECT NVL(MAX(document_version_id), 0) + 1 AS next_version
FROM document
WHERE document_id = #{documentId}

mapper.update:
UPDATE document
created_by = #{createdBy}, title = #{title}, description = #{description},
status_code = #{statusCode},
status_name = #{statusName},
document_version_id = #{documentVersionId}
WHERE document_id = #{documentId}
